import { useEffect, useState, useRef, useCallback } from 'react';
import type { ZodType } from 'zod';

type Status = 'connecting' | 'open' | 'closed' | 'error';

export function useWebSocket<T>(
  url: string,
  options: { schema?: ZodType<T>; onMessage?: (m: T) => void; onError?: (err: unknown) => void } = {}
) {
  const [status, setStatus] = useState<Status>('connecting');
  const wsRef = useRef<WebSocket | null>(null);
  const optionsRef = useRef(options);
  optionsRef.current = options; // CHANGED: stable ref

  useEffect(() => {
    let cancelled = false; // CHANGED: cancellation token
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => { if (!cancelled) setStatus('open'); };
    ws.onclose = () => { if (!cancelled) setStatus('closed'); };
    ws.onerror = () => {
      if (cancelled) return;
      setStatus('error');
      optionsRef.current.onError?.(new Error('WebSocket error'));
    };
    ws.onmessage = (e) => {
      if (cancelled) return;
      try { // CHANGED: try/catch
        const raw = JSON.parse(e.data);
        const parsed = optionsRef.current.schema ? optionsRef.current.schema.parse(raw) : (raw as T);
        optionsRef.current.onMessage?.(parsed);
      } catch (err) { optionsRef.current.onError?.(err); }
    };

    return () => {
      cancelled = true;
      ws.onopen = ws.onclose = ws.onerror = ws.onmessage = null; // CHANGED: detach
      if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) ws.close(1000, 'unmount');
      if (wsRef.current === ws) wsRef.current = null;
    };
  }, [url]);

  const send = useCallback((payload: unknown): boolean => { // CHANGED: guarded
    const ws = wsRef.current;
    if (!ws || ws.readyState !== WebSocket.OPEN) return false;
    ws.send(JSON.stringify(payload));
    return true;
  }, []);

  return { status, send };
}

