import { useEffect, useState, useDeferredValue, useTransition } from 'react';

type Result = { id: string; title: string };

export function SearchResults({ query }: { query: string }) {
  const deferredQuery = useDeferredValue(query); // CHANGED
  const [results, setResults] = useState<Result[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition(); // CHANGED

  useEffect(() => {
    if (deferredQuery.length <= 1) { setResults([]); setError(null); return; }
    const controller = new AbortController(); // CHANGED
    (async () => {
      try {
        const res = await fetch(`/api/search?q=${encodeURIComponent(deferredQuery)}`, { signal: controller.signal });
        if (!res.ok) throw new Error(`Search failed: ${res.status}`); // CHANGED
        const data = await res.json();
        if (!Array.isArray(data.results)) throw new Error('Malformed response');
        startTransition(() => { setResults(data.results); setError(null); });
      } catch (err) {
        if ((err as Error).name === 'AbortError') return;
        setError((err as Error).message);
      }
    })();
    return () => controller.abort(); // CHANGED
  }, [deferredQuery]);

  if (error) return <div role="alert" className="text-red-600">{error}</div>;
  if (isPending && results.length === 0) return <div>Loading...</div>;
  if (!isPending && results.length === 0 && deferredQuery.length > 1) {
    return <div className="text-neutral-500">No results for "{deferredQuery}"</div>;
  }
  return <ul aria-busy={isPending}>{results.map((r) => <li key={r.id}>{r.title}</li>)}</ul>;
}

