import { useState } from 'react';

type Column<T> = {
  key: keyof T;
  header: string;
  render?: (value: any, row: T) => React.ReactNode;
  sortable?: boolean;
};

export function Table<T extends Record<string, any>>({ data, columns }: { data: T[]; columns: Column<T>[] }) {
  const [sortKey, setSortKey] = useState<keyof T | null>(null);
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');

  const sorted = sortKey
    ? [...data].sort((a, b) => {
        const av = a[sortKey] as any;
        const bv = b[sortKey] as any;
        return sortDir === 'asc' ? (av > bv ? 1 : -1) : (av < bv ? 1 : -1);
      })
    : data;

  return (
    <table className="w-full">
      <thead>
        <tr>{columns.map((col) => (
          <th key={col.key as string} onClick={() => {
            if (!col.sortable) return;
            if (sortKey === col.key) setSortDir((d) => d === 'asc' ? 'desc' : 'asc');
            else setSortKey(col.key);
          }}>{col.header}</th>
        ))}</tr>
      </thead>
      <tbody>{sorted.map((row, i) => (
        <tr key={i}>{columns.map((col) => (
          <td key={col.key as string}>{col.render ? col.render(row[col.key], row) : (row[col.key] as React.ReactNode)}</td>
        ))}</tr>
      ))}</tbody>
    </table>
  );
}

