import { useState } from 'react';
import type { ReactNode } from 'react';

type Column<T> = { [K in keyof T]: {
  key: K;
  header: string;
  render?: (value: T[K], row: T) => ReactNode;
  sortable?: boolean;
  compare?: (a: T[K], b: T[K]) => number;
}}[keyof T];

function defaultCompare(a: unknown, b: unknown): number {
  if (a === b) return 0;
  if (a == null) return -1;
  if (b == null) return 1;
  if (typeof a === 'number' && typeof b === 'number') return a - b;
  if (a instanceof Date && b instanceof Date) return a.getTime() - b.getTime();
  return String(a).localeCompare(String(b));
}

export function Table<T extends Record<string, unknown>>({ data, columns, getRowId }: {
  data: T[]; columns: Column<T>[]; getRowId: (row: T) => string;
}) {
  const [sortKey, setSortKey] = useState<keyof T | null>(null);
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');

  const sorted = sortKey
    ? [...data].sort((a, b) => {
        const col = columns.find((c) => c.key === sortKey);
        const cmp = col && 'compare' in col && col.compare
          ? col.compare(a[sortKey] as never, b[sortKey] as never)
          : defaultCompare(a[sortKey], b[sortKey]);
        return sortDir === 'asc' ? cmp : -cmp;
      })
    : data;

  return (
    <table className="w-full">
      <thead><tr>{columns.map((col) => {
        const active = sortKey === col.key;
        const ariaSort = !col.sortable ? undefined : active ? (sortDir === 'asc' ? 'ascending' : 'descending') : 'none';
        return (
          <th key={String(col.key)} aria-sort={ariaSort} scope="col">
            {col.sortable ? (
              <button type="button" onClick={() => {
                if (active) setSortDir((d) => d === 'asc' ? 'desc' : 'asc');
                else { setSortKey(col.key); setSortDir('asc'); }
              }} className="flex items-center gap-1">
                {col.header}
                {active && <span aria-hidden>{sortDir === 'asc' ? '\u25B2' : '\u25BC'}</span>}
              </button>
            ) : col.header}
          </th>
        );
      })}</tr></thead>
      <tbody>{sorted.map((row) => (
        <tr key={getRowId(row)}>
          {columns.map((col) => (
            <td key={String(col.key)}>
              {col.render ? col.render(row[col.key] as never, row) : String(row[col.key] ?? '')}
            </td>
          ))}
        </tr>
      ))}</tbody>
    </table>
  );
}

