import { createContext, useContext, useEffect, useMemo, useState, useCallback, ReactNode } from 'react';

type Theme = 'light' | 'dark' | 'system'; // CHANGED
type ThemeContextValue = { theme: Theme; resolvedTheme: 'light' | 'dark'; setTheme: (t: Theme) => void };

const ThemeContext = createContext<ThemeContextValue | null>(null); // CHANGED: nullable, throw on miss

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() => {
    if (typeof window === 'undefined') return 'system';
    return (localStorage.getItem('theme') as Theme) || 'system'; // CHANGED: persist
  });
  const [systemDark, setSystemDark] = useState(() =>
    typeof window !== 'undefined' && window.matchMedia('(prefers-color-scheme: dark)').matches
  );

  useEffect(() => {
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    const fn = (e: MediaQueryListEvent) => setSystemDark(e.matches);
    mq.addEventListener('change', fn);
    return () => mq.removeEventListener('change', fn);
  }, []);

  const resolvedTheme: 'light' | 'dark' = theme === 'system' ? (systemDark ? 'dark' : 'light') : theme;

  useEffect(() => {
    document.documentElement.classList.toggle('dark', resolvedTheme === 'dark');
    localStorage.setItem('theme', theme);
  }, [theme, resolvedTheme]);

  const setTheme = useCallback((t: Theme) => setThemeState(t), []);

  // CHANGED: useMemo so consumers don't re-render on unrelated parent renders
  const value = useMemo(() => ({ theme, resolvedTheme, setTheme }), [theme, resolvedTheme, setTheme]);

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme(): ThemeContextValue {
  const v = useContext(ThemeContext);
  if (!v) throw new Error('useTheme must be used within ThemeProvider'); // CHANGED
  return v;
}

