import { useState } from 'react';

export function SignupForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!email.includes('@')) { setError('Invalid email'); return; }
    if (password.length < 8) { setError('Password too short'); return; }
    setSubmitting(true);
    const res = await fetch('/api/signup', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password }),
    });
    if (res.ok) window.location.href = '/welcome';
    else setError('Signup failed');
    setSubmitting(false);
  }

  return (
    <form onSubmit={handleSubmit}>
      <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" />
      <input value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" />
      <button disabled={submitting}>{submitting ? 'Submitting...' : 'Sign up'}</button>
      {error && <div className="text-red-500">{error}</div>}
    </form>
  );
}

