import React from 'react';
import * as Sentry from '@sentry/react';

type Props = React.PropsWithChildren<{ resetKeys?: unknown[] }>;
type State = { hasError: boolean; error: Error | null };

export class ErrorBoundary extends React.Component<Props, State> {
  state: State = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    // CHANGED: send to Sentry with React component stack
    Sentry.captureException(error, { extra: { componentStack: errorInfo.componentStack } });
  }

  componentDidUpdate(prev: Props) {
    // CHANGED: reset on resetKeys change (e.g., pathname)
    if (this.state.hasError && prev.resetKeys && this.props.resetKeys) {
      const changed = prev.resetKeys.some((k, i) => !Object.is(k, this.props.resetKeys![i]));
      if (changed) this.reset();
    }
  }

  reset = () => this.setState({ hasError: false, error: null });

  render() {
    if (this.state.hasError) {
      // CHANGED: accessible, recoverable
      return (
        <div role="alert" className="p-6">
          <h2 className="text-lg font-semibold">Something went wrong</h2>
          <p className="text-sm text-neutral-600">{this.state.error?.message}</p>
          <button type="button" onClick={this.reset} className="mt-3 px-3 py-1 border rounded">
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

// CHANGED: bridge async errors into render path. Mount once near the root.
export function useGlobalErrorReporter() {
  React.useEffect(() => {
    const onError = (e: ErrorEvent) => Sentry.captureException(e.error);
    const onRejection = (e: PromiseRejectionEvent) => Sentry.captureException(e.reason);
    window.addEventListener('error', onError);
    window.addEventListener('unhandledrejection', onRejection);
    return () => {
      window.removeEventListener('error', onError);
      window.removeEventListener('unhandledrejection', onRejection);
    };
  }, []);
}

