import { useEffect, useRef, useState, useCallback } from 'react';

type Options<T> = { intervalMs: number; transform?: (data: unknown) => T; onError?: (err: unknown) => void };

export function usePolling<T>(url: string, options: Options<T>) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<unknown>(null);

  // CHANGED: stable refs so transform/onError changes don't restart polling
  const optRef = useRef(options);
  optRef.current = options;

  useEffect(() => {
    let active = true;
    let timer: ReturnType<typeof setTimeout> | null = null;
    let failures = 0;
    setData(null); // CHANGED: clear on url change

    async function tick() {
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const json = await res.json();
        if (!active) return;
        const t = optRef.current.transform;
        setData(t ? t(json) : (json as T));
        setError(null);
        failures = 0;
      } catch (err) {
        if (!active) return;
        failures += 1;
        setError(err);
        optRef.current.onError?.(err);
      } finally {
        if (!active) return;
        // CHANGED: chained setTimeout with backoff, never overlap
        const delay = Math.min(optRef.current.intervalMs * 2 ** Math.min(failures, 5), 60_000);
        timer = setTimeout(tick, failures === 0 ? optRef.current.intervalMs : delay);
      }
    }

    function onVisibility() {
      // CHANGED: pause when hidden, immediate tick on visible
      if (document.visibilityState === 'hidden') {
        if (timer) clearTimeout(timer);
      } else {
        if (timer) clearTimeout(timer);
        tick();
      }
    }

    tick();
    document.addEventListener('visibilitychange', onVisibility);
    return () => {
      active = false;
      if (timer) clearTimeout(timer);
      document.removeEventListener('visibilitychange', onVisibility);
    };
  }, [url, options.intervalMs]); // CHANGED: intervalMs is in the contract; transform via ref

  return { data, error };
}

