export function OrderDetail({ orderId }: { orderId: string }) {
  const [order, setOrder] = useState<any>(null);
  const [history, setHistory] = useState<any[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<any[]>([]);
  const [editingAddress, setEditingAddress] = useState(false);
  const [addressDraft, setAddressDraft] = useState<any>({});
  const [refundOpen, setRefundOpen] = useState(false);
  const [refundAmount, setRefundAmount] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetch(`/api/orders/${orderId}`).then((r) => r.json()).then(setOrder);
    fetch(`/api/orders/${orderId}/history`).then((r) => r.json()).then(setHistory);
    fetch(`/api/users/${orderId}/payment-methods`).then((r) => r.json()).then(setPaymentMethods);
  }, [orderId]);

  async function saveAddress() {
    setSaving(true);
    await fetch(`/api/orders/${orderId}/address`, {
      method: 'POST',
      body: JSON.stringify(addressDraft),
    });
    setEditingAddress(false);
    setSaving(false);
  }

  async function issueRefund() {
    setSaving(true);
    await fetch(`/api/orders/${orderId}/refunds`, {
      method: 'POST',
      body: JSON.stringify({ amount: refundAmount }),
    });
    setRefundOpen(false);
    setSaving(false);
  }

  if (!order) return <div>Loading...</div>;

  return (
    <div>
      <h1>{order.id}</h1>
      <div>Customer: {order.customer.name}</div>
      <h2>Items</h2>
      <ul>{order.items.map((it: any) => <li key={it.id}>{it.name} x {it.qty} = ${it.price * it.qty}</li>)}</ul>
      <h2>Total: ${order.items.reduce((s: number, it: any) => s + it.price * it.qty, 0)}</h2>
      <h2>Address</h2>
      {editingAddress ? (
        <div>
          <input value={addressDraft.line1 || ''} onChange={(e) => setAddressDraft({ ...addressDraft, line1: e.target.value })} />
          <button onClick={saveAddress}>Save</button>
        </div>
      ) : (
        <div>{order.address.line1}<button onClick={() => { setEditingAddress(true); setAddressDraft(order.address); }}>Edit</button></div>
      )}
      <h2>Payment</h2>
      {paymentMethods.map((p: any) => <div key={p.id}>{p.brand} **** {p.last4}</div>)}
      <button onClick={() => setRefundOpen(true)}>Refund</button>
      {refundOpen && (
        <div><input value={refundAmount} onChange={(e) => setRefundAmount(e.target.value)} /><button onClick={issueRefund}>Issue</button></div>
      )}
      <h2>History</h2>
      <ul>{history.map((h: any) => <li key={h.id}>{h.action} at {h.at}</li>)}</ul>
    </div>
  );
