import { useEffect, useState } from 'react';

const rtf = new Intl.RelativeTimeFormat(undefined, { numeric: 'auto' });

function formatRelative(diffMs: number): string {
  const sec = Math.round(diffMs / 1000);
  if (Math.abs(sec) < 60) return rtf.format(-sec, 'second');
  const min = Math.round(sec / 60);
  if (Math.abs(min) < 60) return rtf.format(-min, 'minute');
  const hr = Math.round(min / 60);
  if (Math.abs(hr) < 24) return rtf.format(-hr, 'hour');
  return ''; // fall through to absolute
}

export function LastSeen({ timestamp }: { timestamp: number }) {
  // CHANGED: render stable absolute on first paint (server + first client render)
  const iso = new Date(timestamp).toISOString();
  const [relative, setRelative] = useState<string | null>(null);

  useEffect(() => {
    // CHANGED: schedule precisely to the next boundary; pause when hidden
    let timer: ReturnType<typeof setTimeout> | null = null;
    function tick() {
      const diff = Date.now() - timestamp;
      const rel = formatRelative(diff);
      setRelative(rel);
      // schedule next tick at next 'boundary'
      const sec = Math.abs(diff) / 1000;
      const nextMs = sec < 60 ? 1000 : sec < 3600 ? 60_000 : 3_600_000;
      timer = setTimeout(tick, nextMs);
    }
    function onVis() {
      if (document.visibilityState === 'visible') {
        if (timer) clearTimeout(timer);
        tick();
      } else if (timer) clearTimeout(timer);
    }
    tick();
    document.addEventListener('visibilitychange', onVis);
    return () => {
      if (timer) clearTimeout(timer);
      document.removeEventListener('visibilitychange', onVis);
    };
  }, [timestamp]);

  return (
    // CHANGED: semantic <time>, title for exact, dateTime for parsers
    <time dateTime={iso} title={new Date(timestamp).toLocaleString()}>
      {relative ?? new Date(timestamp).toLocaleDateString(undefined, { dateStyle: 'medium' })}
    </time>
  );
}

