import { useCallback, useRef, useState } from 'react';

type Size = { width: number; height: number };

export function useResizeObserver<T extends HTMLElement>() {
  const [size, setSize] = useState<Size>({ width: 0, height: 0 });
  const observerRef = useRef<ResizeObserver | null>(null);

  // CHANGED: callback ref so we react to element attach/detach
  const ref = useCallback((node: T | null) => {
    if (observerRef.current) {
      observerRef.current.disconnect();
      observerRef.current = null;
    }
    if (!node) return;
    // Seed synchronously to avoid 0,0 flash
    const rect = node.getBoundingClientRect();
    setSize({ width: rect.width, height: rect.height });

    const observer = new ResizeObserver((entries) => {
      // CHANGED: find entry for node; defer with rAF to avoid loop limit
      const entry = entries.find((e) => e.target === node) ?? entries[entries.length - 1];
      if (!entry) return;
      const w = entry.contentRect.width;
      const h = entry.contentRect.height;
      requestAnimationFrame(() => {
        // CHANGED: equality check
        setSize((prev) => (prev.width === w && prev.height === h ? prev : { width: w, height: h }));
      });
    });
    observer.observe(node);
    observerRef.current = observer;
  }, []);

  return { ref, size }; // CHANGED: object return
}

