import { useEffect, useRef, useState } from 'react';

export function EditableField({ initial, onSave }: { initial: string; onSave: (v: string, signal?: AbortSignal) => Promise<void> }) {
  const [value, setValue] = useState(initial);
  const [lastSaved, setLastSaved] = useState(initial); // CHANGED: track saved state independent of prop
  const [status, setStatus] = useState<'idle' | 'saving' | 'error' | 'saved'>('idle');
  const abortRef = useRef<AbortController | null>(null);

  // CHANGED: sync external prop updates (parent refetch) when not actively editing
  useEffect(() => {
    if (status !== 'saving' && value === lastSaved) {
      setValue(initial);
      setLastSaved(initial);
    }
  }, [initial, status, value, lastSaved]);

  async function handleBlur(e: React.FocusEvent<HTMLInputElement>) {
    // CHANGED: skip if focus moved within our component
    if (e.currentTarget.contains(e.relatedTarget as Node)) return;
    if (value === lastSaved) return;

    abortRef.current?.abort(); // CHANGED: cancel any in-flight save
    const controller = new AbortController();
    abortRef.current = controller;

    setStatus('saving');
    try {
      await onSave(value, controller.signal);
      if (controller.signal.aborted) return;
      setLastSaved(value);
      setStatus('saved');
    } catch (err) {
      if ((err as Error).name === 'AbortError') return;
      setStatus('error');
    }
  }

  return (
    <div>
      <input
        value={value}
        onChange={(e) => { setValue(e.target.value); if (status === 'saved' || status === 'error') setStatus('idle'); }}
        onBlur={handleBlur}
