const MAX_QTY = 99;

export const useCart = create<CartState>()(
  persist(
    (set, get) => ({
      items: [],
      hydrated: false,
      add: (item) => set((s) => {
        // CHANGED: single atomic set
        const existing = s.items.find((i) => i.id === item.id);
        if (existing) {
          return { items: s.items.map((i) => i.id === item.id ? { ...i, qty: Math.min(i.qty + 1, MAX_QTY) } : i) };
        }
        return { items: [...s.items, { ...item, qty: 1 }] };
