import { useEffect, useRef, useState, useTransition } from 'react';
import { z } from 'zod';

const Step1 = z.object({ name: z.string().min(1), email: z.string().email() });
const Step2 = z.object({ address: z.string().min(1), city: z.string().min(1) });
const Step3 = z.object({ agree: z.literal(true) });
const schemas = [Step1, Step2, Step3] as const;

type FormData = z.infer<typeof Step1> & z.infer<typeof Step2> & z.infer<typeof Step3>;
const STORAGE_KEY = 'wizard-draft';

export function Wizard() {
  const [step, setStep] = useState(0);
  const [data, setData] = useState<FormData>(() => {
    if (typeof window === 'undefined') return { name: '', email: '', address: '', city: '', agree: false } as any;
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { name: '', email: '', address: '', city: '', agree: false };
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isPending, startTransition] = useTransition();
  const lockRef = useRef(false);
  const firstFieldRef = useRef<HTMLInputElement>(null);

  // CHANGED: persist on every change
  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); }, [data]);

  // CHANGED: warn on unload while dirty
  useEffect(() => {
    const handler = (e: BeforeUnloadEvent) => { e.preventDefault(); };
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, []);

  function update<K extends keyof FormData>(key: K, value: FormData[K]) {
    setData((prev) => ({ ...prev, [key]: value })); // CHANGED: updater form
    setErrors((prev) => ({ ...prev, [key]: '' }));
  }

  function next() {
    const result = schemas[step].safeParse(data);
    if (!result.success) {
      const fieldErrors: Record<string, string> = {};
      for (const issue of result.error.issues) fieldErrors[issue.path[0] as string] = issue.message;
      setErrors(fieldErrors);
      firstFieldRef.current?.focus(); // CHANGED: focus first invalid
      return;
    }
    setStep((s) => s + 1);
  }

  async function submit() {
    if (lockRef.current) return; // CHANGED: double-submit lock
    lockRef.current = true;
    try {
      const res = await fetch('/api/wizard', { method: 'POST', body: JSON.stringify(data) });
      if (!res.ok) throw new Error('Submit failed');
      localStorage.removeItem(STORAGE_KEY);
      // navigate to success
    } catch (err) {
      setErrors({ submit: (err as Error).message });
    } finally {
      lockRef.current = false;
    }
  }

  return (
    <div>
      <p aria-live="polite" className="text-sm">Step {step + 1} of 3</p> {/* CHANGED: a11y announce */}
      {/* ...steps rendered using update() and aria-invalid + error messages... */}
      <div className="flex gap-2">
        {step > 0 && <button type="button" onClick={() => setStep((s) => s - 1)}>Back</button>}
        {step < 2 ? (
          <button type="button" onClick={next}>Next</button>
        ) : (
          <button type="button" onClick={() => startTransition(submit)} disabled={isPending}>
            {isPending ? 'Submitting…' : 'Submit'}
          </button>
        )}
      </div>
      {errors.submit && <div role="alert">{errors.submit}</div>}
    </div>
  );
}

