import { useEffect, useRef, useState } from 'react';

export function FadeInCard({ children, index }: { children: React.ReactNode; index: number }) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);
  const [reducedMotion, setReducedMotion] = useState(false);

  // CHANGED: respect reduced motion
  useEffect(() => {
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReducedMotion(mq.matches);
    const handler = (e: MediaQueryListEvent) => setReducedMotion(e.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  useEffect(() => {
    if (!ref.current) return;
    if (reducedMotion) { setVisible(true); return; } // CHANGED: skip animation

    let timeoutId: ReturnType<typeof setTimeout> | null = null;
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting && !visible) {
          timeoutId = setTimeout(() => setVisible(true), index * 100);
          observer.unobserve(entry.target); // CHANGED: don't re-animate
        }
      });
    });
    observer.observe(ref.current);
    return () => {
      if (timeoutId) clearTimeout(timeoutId); // CHANGED: cleanup timeout
      observer.disconnect();
    };
  }, [index, reducedMotion, visible]);

  return (
    <div
      ref={ref}
      aria-hidden={!visible || undefined} // CHANGED: hide from a11y tree while invisible
      className={`transition-opacity duration-500 motion-reduce:transition-none ${visible ? 'opacity-100' : 'opacity-0 invisible'}`}
    >
      {children}
    </div>
  );
}

