import { useEffect, useRef, useState } from 'react';

type Status = 'idle' | 'saving' | 'saved' | 'error';

export function useAutoSave<T>(
  data: T,
  save: (d: T, signal: AbortSignal) => Promise<void>,
  delayMs = 2000
) {
  const saveRef = useRef(save); // CHANGED: stabilize save callback
  saveRef.current = save;

  const [status, setStatus] = useState<Status>('idle');
  const [lastSavedAt, setLastSavedAt] = useState<number | null>(null);
  const [error, setError] = useState<unknown>(null);
  const inFlightRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const timerId = setTimeout(async () => {
      inFlightRef.current?.abort(); // CHANGED: cancel previous
      const controller = new AbortController();
      inFlightRef.current = controller;
      setStatus('saving');
      try {
        await saveRef.current(data, controller.signal);
        if (controller.signal.aborted) return;
        setStatus('saved');
        setLastSavedAt(Date.now());
        setError(null);
      } catch (err) {
        if ((err as Error).name === 'AbortError') return;
        setStatus('error');
        setError(err);
      }
    }, delayMs);

    return () => {
      clearTimeout(timerId);
      // Note: don't abort in-flight here — let the save complete; the next save will cancel it if needed.
    };
  }, [data, delayMs]); // CHANGED: save excluded; read via ref

  return { status, lastSavedAt, error };
}

