import { useEffect, useRef, useState } from 'react';

const MAX_BYTES = 15 * 1024 * 1024;
const MAX_DIMENSION = 1200;
const SUPPORTED = new Set(['image/jpeg', 'image/png', 'image/webp']);

export function ImageUploader({ onUpload }: { onUpload: (blob: Blob) => void }) {
  const [preview, setPreview] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const lastPreviewRef = useRef<string | null>(null);

  useEffect(() => () => { // CHANGED: cleanup on unmount
    if (lastPreviewRef.current) URL.revokeObjectURL(lastPreviewRef.current);
  }, []);

  async function handleFile(e: React.ChangeEvent<HTMLInputElement>) {
    setError(null);
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > MAX_BYTES) return setError('File too large (max 15MB).'); // CHANGED: size check
    if (!SUPPORTED.has(file.type)) return setError('Use JPEG, PNG, or WebP. HEIC files need conversion.'); // CHANGED: format check

    try {
      // CHANGED: createImageBitmap handles EXIF orientation and is more memory-efficient
      const bitmap = await createImageBitmap(file, { imageOrientation: 'from-image' });
      const ratio = Math.min(1, MAX_DIMENSION / Math.max(bitmap.width, bitmap.height));
      const w = Math.round(bitmap.width * ratio);
      const h = Math.round(bitmap.height * ratio);

      const canvas = document.createElement('canvas');
      canvas.width = w;
      canvas.height = h;
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error('Canvas unsupported');
      ctx.drawImage(bitmap, 0, 0, w, h);
      bitmap.close(); // CHANGED: free memory

      const blob = await new Promise<Blob | null>((res) => canvas.toBlob(res, 'image/jpeg', 0.8));
      if (!blob) throw new Error('Failed to encode image');

      // CHANGED: revoke previous preview before assigning new one
      if (lastPreviewRef.current) URL.revokeObjectURL(lastPreviewRef.current);
      const url = URL.createObjectURL(blob);
      lastPreviewRef.current = url;
      setPreview(url);
      onUpload(blob);
    } catch (err) {
      setError((err as Error).message);
    }
  }

  return (
    <div>
      <input type="file" accept="image/jpeg,image/png,image/webp" onChange={handleFile} />
      {error && <div role="alert" className="text-red-600">{error}</div>}
      {preview && <img src={preview} alt="Image preview" className="max-w-xs" />}
    </div>
  );
}
